  1→package main
  2→
  3→import (
  4→	"flag"
  5→	"fmt"
  6→	"os"
  7→	"strconv"
  8→	"strings"
  9→)
 10→
 11→// summaryFlag implements flag.Value for -s, acting as a bool flag that also accepts
 12→// an optional range: -s, -s=5, -s=5:10, -s=:10, -s=5:
 13→type summaryFlag struct {
 14→	enabled bool
 15→	from    int
 16→	to      int
 17→}
 18→
 19→func (f *summaryFlag) String() string { return "" }
 20→
 21→func (f *summaryFlag) Set(s string) error {
 22→	if s == "true" || s == "" {
 23→		f.enabled = true
 24→		return nil
 25→	}
 26→	if s == "false" {
 27→		f.enabled = false
 28→		return nil
 29→	}
 30→	f.enabled = true
 31→	if before, after, ok := strings.Cut(s, ":"); ok {
 32→		if before != "" {
 33→			n, err := strconv.Atoi(before)
 34→			if err != nil {
 35→				return fmt.Errorf("invalid range: %s", s)
 36→			}
 37→			f.from = n
 38→		}
 39→		if after != "" {
 40→			n, err := strconv.Atoi(after)
 41→			if err != nil {
 42→				return fmt.Errorf("invalid range: %s", s)
 43→			}
 44→			f.to = n
 45→		}
 46→	} else {
 47→		n, err := strconv.Atoi(s)
 48→		if err != nil {
 49→			return fmt.Errorf("invalid range: %s", s)
 50→		}
 51→		f.from = n
 52→	}
 53→	return nil
 54→}
 55→
 56→func (f *summaryFlag) IsBoolFlag() bool { return true }
 57→
 58→// reorderArgs moves flags before positional arguments in os.Args[1:],
 59→// so Go's flag package (which stops at the first non-flag) parses them all.
 60→func reorderArgs() {
 61→	// Flags that take a following argument (not using =)
 62→	withValue := map[string]bool{
 63→		"-o": true, "-n": true, "-from": true, "-to": true, "-last": true, "-images": true,
 64→	}
 65→	var flags, positional []string
 66→	args := os.Args[1:]
 67→	for i := 0; i < len(args); i++ {
 68→		a := args[i]
 69→		if strings.HasPrefix(a, "-") {
 70→			flags = append(flags, a)
 71→			// If this flag takes a separate value and doesn't use =, consume next arg too
 72→			if withValue[a] && !strings.Contains(a, "=") && i+1 < len(args) {
 73→				i++
 74→				flags = append(flags, args[i])
 75→			}
 76→		} else {
 77→			positional = append(positional, a)
 78→		}
 79→	}
 80→	copy(os.Args[1:], append(flags, positional...))
 81→}
 82→
 83→func main() {
 84→	if len(os.Args) >= 2 {
 85→		switch os.Args[1] {
 86→		case "claude":
 87→			runClaude(os.Args[2:])
 88→			return
 89→		case "fastcompact":
 90→			fastcompact(os.Args[2:])
 91→			return
 92→		case "precompact":
 93→			precompact()
 94→			return
 95→		}
 96→	}
 97→
 98→	// Reorder os.Args so flags come before positional args.
 99→	// Go's flag package stops parsing at the first non-flag argument,
100→	// so "ccmd 1 -s -last 20" would fail without this.
101→	reorderArgs()
102→
103→	outputFile := flag.String("o", "", "write output to file instead of stdout")
104→	numSessions := flag.Int("n", 0, "limit number of sessions to list (0 = all)")
105→	hideThinking := flag.Bool("no-thinking", false, "hide thinking blocks from output")
106→	var summary summaryFlag
107→	flag.Var(&summary, "s", "summary mode: -s, -s=FROM:TO, -s=FROM:, -s=:TO, -s=N")
108→	fromTurn := flag.Int("from", 0, "start turn number (inclusive)")
109→	toTurn := flag.Int("to", 0, "end turn number (inclusive)")
110→	lastTurns := flag.Int("last", 0, "show only the last N turns")
111→	imagesDir := flag.String("images", "", "extract images to this directory")
112→	flag.Usage = func() {
113→		fmt.Fprintf(os.Stderr, "Usage: ccmd [flags] [session-file-or-number-or-uuid]\n\n")
114→		fmt.Fprintf(os.Stderr, "Parse Claude Code JSONL session files into Markdown.\n\n")
115→		fmt.Fprintf(os.Stderr, "Commands:\n")
116→		fmt.Fprintf(os.Stderr, "  ccmd claude ...  launch claude with fastcompact support\n")
117→		fmt.Fprintf(os.Stderr, "  ccmd fastcompact render & restart the most recent session\n\n")
118→		fmt.Fprintf(os.Stderr, "Session browser:\n")
119→		fmt.Fprintf(os.Stderr, "  No arguments     interactive session browser (plain list if piped)\n")
120→		fmt.Fprintf(os.Stderr, "  <number>         render the Nth most recent session\n")
121→		fmt.Fprintf(os.Stderr, "  <uuid>           render the session with that UUID\n")
122→		fmt.Fprintf(os.Stderr, "  <path>           render the session at that path\n\n")
123→		fmt.Fprintf(os.Stderr, "Flags:\n")
124→		flag.PrintDefaults()
125→	}
126→	flag.Parse()
127→
128→	// -s=FROM:TO overrides -from/-to
129→	if summary.from > 0 && *fromTurn == 0 {
130→		*fromTurn = summary.from
131→	}
132→	if summary.to > 0 && *toTurn == 0 {
133→		*toTurn = summary.to
134→	}
135→
136→	if flag.NArg() == 0 {
137→		if isTerminal() {
138→			runTUI(*numSessions, !*hideThinking, *fromTurn, *toTurn)
139→		} else {
140→			listSessions(*numSessions, "")
141→		}
142→		return
143→	}
144→
145→	arg := flag.Arg(0)
146→
147→	// "parent" resolves to the UUID from CCMD_PARENT_UUID env var
148→	if arg == "parent" {
149→		parentUUID := os.Getenv("CCMD_PARENT_UUID")
150→		if parentUUID == "" {
151→			fmt.Fprintf(os.Stderr, "error: CCMD_PARENT_UUID not set\n")
152→			os.Exit(1)
153→		}
154→		arg = parentUUID
155→	}
156→
157→	// If the argument is a number, look it up from the session list
158→	if n, err := strconv.Atoi(arg); err == nil {
159→		sessions := findSessions(0, cwdProjectDir())
160→		if n < 1 || n > len(sessions) {
161→			fmt.Fprintf(os.Stderr, "error: session %d not found (have %d sessions)\n", n, len(sessions))
162→			os.Exit(1)
163→		}
164→		arg = sessions[n-1].Path
165→	} else if isUUID(arg) {
166→		found := findSessionByUUID(arg)
167→		if found == "" {
168→			fmt.Fprintf(os.Stderr, "error: no session found for UUID %s\n", arg)
169→			os.Exit(1)
170→		}
171→		arg = found
172→	}
173→
174→	renderSession(arg, *outputFile, *imagesDir, !*hideThinking, summary.enabled, *fromTurn, *toTurn, *lastTurns)
175→}
