  1→package main
  2→
  3→import (
  4→	"bufio"
  5→	"encoding/base64"
  6→	"encoding/json"
  7→	"fmt"
  8→	"io"
  9→	"os"
 10→	"path/filepath"
 11→	"strings"
 12→	"time"
 13→)
 14→
 15→func parseRecords(r io.Reader) []Record {
 16→	var records []Record
 17→	scanner := bufio.NewScanner(r)
 18→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
 19→
 20→	for scanner.Scan() {
 21→		var rec Record
 22→		if err := json.Unmarshal(scanner.Bytes(), &rec); err != nil {
 23→			continue
 24→		}
 25→		records = append(records, rec)
 26→	}
 27→	return records
 28→}
 29→
 30→func parseContent(raw json.RawMessage) (string, []ContentBlock) {
 31→	if len(raw) == 0 {
 32→		return "", nil
 33→	}
 34→	// Try string first (user messages)
 35→	var s string
 36→	if err := json.Unmarshal(raw, &s); err == nil {
 37→		return s, nil
 38→	}
 39→	// Try array of content blocks
 40→	var blocks []ContentBlock
 41→	if err := json.Unmarshal(raw, &blocks); err == nil {
 42→		return "", blocks
 43→	}
 44→	return "", nil
 45→}
 46→
 47→func buildConversation(records []Record, sessionPath string, isSubagent bool, imagesDir string) []ConversationEntry {
 48→	// Build tool_use_id -> agentId map from progress records
 49→	agentMap := make(map[string]string) // tool_use_id -> agentId
 50→	for _, rec := range records {
 51→		if rec.Type != "progress" || len(rec.Data) == 0 {
 52→			continue
 53→		}
 54→		var data struct {
 55→			Type    string `json:"type"`
 56→			AgentID string `json:"agentId"`
 57→		}
 58→		if json.Unmarshal(rec.Data, &data) == nil && data.Type == "agent_progress" && data.AgentID != "" {
 59→			agentMap[rec.ParentToolUseID] = data.AgentID
 60→		}
 61→	}
 62→
 63→	// Collect tool result errors/rejections: tool_use_id -> error message
 64→	toolErrors := make(map[string]string)
 65→	// Collect tool result metadata: tool_use_id -> summary string (e.g. line count)
 66→	toolMeta := make(map[string]string)
 67→	for _, rec := range records {
 68→		if rec.Type != "user" || rec.Message == nil {
 69→			continue
 70→		}
 71→		// Parse toolUseResult for metadata
 72→		if len(rec.ToolUseResult) > 0 {
 73→			var result map[string]json.RawMessage
 74→			if json.Unmarshal(rec.ToolUseResult, &result) == nil {
 75→				// Read: {file: {totalLines: N}}
 76→				if fileRaw, ok := result["file"]; ok {
 77→					var file struct {
 78→						TotalLines int `json:"totalLines"`
 79→					}
 80→					if json.Unmarshal(fileRaw, &file) == nil && file.TotalLines > 0 {
 81→						_, blocks := parseContent(rec.Message.Content)
 82→						for _, b := range blocks {
 83→							if b.Type == "tool_result" && b.ToolUseID != "" {
 84→								toolMeta[b.ToolUseID] = fmt.Sprintf("%d lines", file.TotalLines)
 85→							}
 86→						}
 87→					}
 88→				}
 89→				// Glob: {numFiles: N}
 90→				if numRaw, ok := result["numFiles"]; ok {
 91→					var n int
 92→					if json.Unmarshal(numRaw, &n) == nil {
 93→						_, blocks := parseContent(rec.Message.Content)
 94→						for _, b := range blocks {
 95→							if b.Type == "tool_result" && b.ToolUseID != "" {
 96→								toolMeta[b.ToolUseID] = fmt.Sprintf("%d files", n)
 97→							}
 98→						}
 99→					}
100→				}
101→			}
102→		}
103→		_, blocks := parseContent(rec.Message.Content)
104→		for _, b := range blocks {
105→			if b.Type == "tool_result" && b.IsError && b.ToolUseID != "" {
106→				msg := extractToolResultText(b)
107→				if msg != "" {
108→					toolErrors[b.ToolUseID] = msg
109→				}
110→			}
111→		}
112→	}
113→
114→	// First pass: build raw entries, grouping by message ID
115→	var raw []ConversationEntry
116→	seenMsgID := make(map[string]int)
117→	imageNum := 0
118→
119→	for _, rec := range records {
120→		if !isSubagent && rec.IsSidechain {
121→			continue
122→		}
123→
124→		switch rec.Type {
125→		case "system":
126→			if rec.Subtype == "compact_boundary" {
127→				ts, _ := time.Parse(time.RFC3339Nano, rec.Timestamp)
128→				raw = append(raw, ConversationEntry{
129→					Role:      "system",
130→					Texts:     []string{"*— context compacted —*"},
131→					Timestamp: ts,
132→				})
133→			}
134→			continue
135→
136→		case "pr-link":
137→			if rec.PRUrl != "" {
138→				ts, _ := time.Parse(time.RFC3339Nano, rec.Timestamp)
139→				text := fmt.Sprintf("PR created: [%s#%d](%s)", rec.PRRepository, rec.PRNumber, rec.PRUrl)
140→				raw = append(raw, ConversationEntry{
141→					Role:      "system",
142→					Texts:     []string{text},
143→					Timestamp: ts,
144→				})
145→			}
146→			continue
147→		}
148→
149→		if rec.Message == nil {
150→			continue
151→		}
152→
153→		switch rec.Type {
154→		case "user":
155→			text, blocks := parseContent(rec.Message.Content)
156→			var texts []string
157→			if text != "" {
158→				texts = append(texts, text)
159→			}
160→			for _, b := range blocks {
161→				switch b.Type {
162→				case "text":
163→					if b.Text != "" {
164→						texts = append(texts, b.Text)
165→					}
166→				case "image":
167→					if imagesDir != "" && b.Source != nil && b.Source.Data != "" {
168→						if path := saveImage(imagesDir, b.Source, &imageNum); path != "" {
169→							texts = append(texts, fmt.Sprintf("![image](%s)", path))
170→							continue
171→						}
172→					}
173→					texts = append(texts, "[image]")
174→				}
175→			}
176→			if len(texts) > 0 {
177→				ts, _ := time.Parse(time.RFC3339Nano, rec.Timestamp)
178→				raw = append(raw, ConversationEntry{
179→					Role:      "user",
180→					Texts:     texts,
181→					Timestamp: ts,
182→				})
183→			} else if len(blocks) > 0 {
184→				continue
185→			}
186→
187→		case "assistant":
188→			if rec.Message.ID == "" {
189→				continue
190→			}
191→			_, blocks := parseContent(rec.Message.Content)
192→
193→			idx, exists := seenMsgID[rec.Message.ID]
194→			if !exists {
195→				ts, _ := time.Parse(time.RFC3339Nano, rec.Timestamp)
196→				raw = append(raw, ConversationEntry{
197→					Role:      "assistant",
198→					Timestamp: ts,
199→				})
200→				idx = len(raw) - 1
201→				seenMsgID[rec.Message.ID] = idx
202→			}
203→
204→			entry := &raw[idx]
205→			for _, b := range blocks {
206→				switch b.Type {
207→				case "text":
208→					if b.Text != "" {
209→						entry.Texts = append(entry.Texts, b.Text)
210→					}
211→				case "thinking":
212→					if b.Thinking != "" {
213→						entry.Thinking = append(entry.Thinking, b.Thinking)
214→					}
215→				case "tool_use":
216→					tc := formatToolCall(b)
217→					if errMsg, ok := toolErrors[b.ID]; ok {
218→						tc.Error = errMsg
219→					}
220→					if meta, ok := toolMeta[b.ID]; ok {
221→						tc.Meta = meta
222→					}
223→					// Resolve subagent conversation
224→					if b.Name == "Task" || b.Name == "Agent" {
225→						if agentID, ok := agentMap[b.ID]; ok {
226→							tc.SubConversation = loadSubagent(sessionPath, agentID)
227→						}
228→					}
229→					entry.Tools = append(entry.Tools, tc)
230→				}
231→			}
232→		}
233→	}
234→
235→	// Second pass: merge consecutive same-role entries
236→	return mergeEntries(raw)
237→}
238→
239→func loadSubagent(sessionPath, agentID string) []ConversationEntry {
240→	sessionDir := strings.TrimSuffix(sessionPath, ".jsonl")
241→	agentPath := filepath.Join(sessionDir, "subagents", "agent-"+agentID+".jsonl")
242→
243→	f, err := os.Open(agentPath)
244→	if err != nil {
245→		return nil
246→	}
247→	defer f.Close()
248→
249→	records := parseRecords(f)
250→	return buildConversation(records, agentPath, true, "")
251→}
252→
253→func formatToolCall(b ContentBlock) ToolCall {
254→	var params map[string]interface{}
255→	if len(b.Input) > 0 {
256→		json.Unmarshal(b.Input, &params)
257→	}
258→	if params == nil {
259→		return ToolCall{Name: b.Name}
260→	}
261→
262→	switch b.Name {
263→	case "Read":
264→		return ToolCall{Name: "Read", Input: shortPath(strVal(params, "file_path"))}
265→	case "Edit":
266→		return ToolCall{
267→			Name:   "Edit",
268→			Input:  shortPath(strVal(params, "file_path")),
269→			OldStr: strVal(params, "old_string"),
270→			NewStr: strVal(params, "new_string"),
271→		}
272→	case "Write":
273→		return ToolCall{
274→			Name:   "Write",
275→			Input:  shortPath(strVal(params, "file_path")),
276→			NewStr: strVal(params, "content"),
277→		}
278→	case "Glob":
279→		s := strVal(params, "pattern")
280→		if p := strVal(params, "path"); p != "" {
281→			s = shortPath(p) + "/" + s
282→		}
283→		return ToolCall{Name: "Glob", Input: s}
284→	case "Grep":
285→		s := strVal(params, "pattern")
286→		if p := strVal(params, "path"); p != "" {
287→			s += " in " + shortPath(p)
288→		}
289→		return ToolCall{Name: "Grep", Input: s}
290→	case "Bash":
291→		return ToolCall{Name: "Bash", Input: strVal(params, "command")}
292→	case "ExitPlanMode":
293→		return ToolCall{Name: "Plan", Plan: strVal(params, "plan")}
294→	case "Task":
295→		desc := strVal(params, "description")
296→		if desc == "" {
297→			desc = truncate(strVal(params, "prompt"), 120)
298→		}
299→		return ToolCall{Name: "Agent", Input: desc}
300→	case "Agent":
301→		return ToolCall{Name: "Agent", Input: truncate(strVal(params, "prompt"), 120)}
302→	default:
303→		compact, _ := json.Marshal(params)
304→		return ToolCall{Name: b.Name, Input: truncate(string(compact), 150)}
305→	}
306→}
307→
308→func strVal(m map[string]interface{}, key string) string {
309→	if v, ok := m[key]; ok {
310→		if s, ok := v.(string); ok {
311→			return s
312→		}
313→	}
314→	return ""
315→}
316→
317→func extractToolResultText(b ContentBlock) string {
318→	var s string
319→	if json.Unmarshal(b.Content, &s) == nil {
320→		return s
321→	}
322→	var parts []struct {
323→		Type string `json:"type"`
324→		Text string `json:"text"`
325→	}
326→	if json.Unmarshal(b.Content, &parts) == nil {
327→		var texts []string
328→		for _, p := range parts {
329→			if p.Text != "" {
330→				texts = append(texts, p.Text)
331→			}
332→		}
333→		return strings.Join(texts, "\n")
334→	}
335→	return ""
336→}
337→
338→func saveImage(dir string, src *ImageSource, num *int) string {
339→	data, err := base64.StdEncoding.DecodeString(src.Data)
340→	if err != nil {
341→		return ""
342→	}
343→
344→	*num++
345→	ext := ".png"
346→	switch src.MediaType {
347→	case "image/jpeg":
348→		ext = ".jpg"
349→	case "image/gif":
350→		ext = ".gif"
351→	case "image/webp":
352→		ext = ".webp"
353→	}
354→
355→	os.MkdirAll(dir, 0755)
356→	path := filepath.Join(dir, fmt.Sprintf("image-%d%s", *num, ext))
357→	if err := os.WriteFile(path, data, 0644); err != nil {
358→		return ""
359→	}
360→	return path
361→}
