  1→package main
  2→
  3→import (
  4→	"bufio"
  5→	"encoding/json"
  6→	"fmt"
  7→	"os"
  8→	"path/filepath"
  9→	"regexp"
 10→	"sort"
 11→	"strings"
 12→	"time"
 13→
 14→	"golang.org/x/sync/errgroup"
 15→)
 16→
 17→func claudeProjectsDir() string {
 18→	home, err := os.UserHomeDir()
 19→	if err != nil {
 20→		fmt.Fprintf(os.Stderr, "error: %v\n", err)
 21→		os.Exit(1)
 22→	}
 23→	return filepath.Join(home, ".claude", "projects")
 24→}
 25→
 26→func codexSessionsDir() string {
 27→	home, err := os.UserHomeDir()
 28→	if err != nil {
 29→		fmt.Fprintf(os.Stderr, "error: %v\n", err)
 30→		os.Exit(1)
 31→	}
 32→	return filepath.Join(home, ".codex", "sessions")
 33→}
 34→
 35→// cwdProjectDir returns the project directory name for the current working directory.
 36→// e.g., /Users/ramon/src/ccmd -> -Users-ramon-src-ccmd
 37→func cwdProjectDir() string {
 38→	cwd, err := os.Getwd()
 39→	if err != nil {
 40→		return ""
 41→	}
 42→	return strings.ReplaceAll(cwd, "/", "-")
 43→}
 44→
 45→var uuidRe = regexp.MustCompile(`^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$`)
 46→
 47→func isUUID(s string) bool {
 48→	return uuidRe.MatchString(s)
 49→}
 50→
 51→func findSessionByUUID(uuid string) string {
 52→	// Search Claude Code projects
 53→	projectsDir := claudeProjectsDir()
 54→	filename := uuid + ".jsonl"
 55→	projectDirs, err := os.ReadDir(projectsDir)
 56→	if err == nil {
 57→		for _, pd := range projectDirs {
 58→			if !pd.IsDir() {
 59→				continue
 60→			}
 61→			candidate := filepath.Join(projectsDir, pd.Name(), filename)
 62→			if _, err := os.Stat(candidate); err == nil {
 63→				return candidate
 64→			}
 65→		}
 66→	}
 67→
 68→	// Search Codex sessions (files contain UUID in the name)
 69→	codexDir := codexSessionsDir()
 70→	if found := findCodexSessionByUUID(codexDir, uuid); found != "" {
 71→		return found
 72→	}
 73→	return ""
 74→}
 75→
 76→// findCodexSessionByUUID walks the Codex sessions directory for a file containing the UUID.
 77→func findCodexSessionByUUID(root, uuid string) string {
 78→	var result string
 79→	filepath.Walk(root, func(path string, info os.FileInfo, err error) error {
 80→		if err != nil || info.IsDir() {
 81→			return nil
 82→		}
 83→		if strings.HasSuffix(path, ".jsonl") && strings.Contains(filepath.Base(path), uuid) {
 84→			result = path
 85→			return filepath.SkipAll
 86→		}
 87→		return nil
 88→	})
 89→	return result
 90→}
 91→
 92→func findSessions(limit int, projectFilter string) []SessionInfo {
 93→	type candidate struct {
 94→		path       string
 95→		projectDir string
 96→		modTime    time.Time
 97→		format     SessionFormat
 98→	}
 99→	var candidates []candidate
100→
101→	// Discover Claude Code sessions
102→	projectsDir := claudeProjectsDir()
103→	projectDirs, err := os.ReadDir(projectsDir)
104→	if err == nil {
105→		for _, pd := range projectDirs {
106→			if !pd.IsDir() {
107→				continue
108→			}
109→			if projectFilter != "" && pd.Name() != projectFilter {
110→				continue
111→			}
112→			projPath := filepath.Join(projectsDir, pd.Name())
113→			entries, err := os.ReadDir(projPath)
114→			if err != nil {
115→				continue
116→			}
117→			for _, e := range entries {
118→				if e.IsDir() || !strings.HasSuffix(e.Name(), ".jsonl") {
119→					continue
120→				}
121→				fi, err := e.Info()
122→				if err != nil {
123→					continue
124→				}
125→				candidates = append(candidates, candidate{
126→					path:       filepath.Join(projPath, e.Name()),
127→					projectDir: pd.Name(),
128→					modTime:    fi.ModTime(),
129→					format:     FormatClaudeCode,
130→				})
131→			}
132→		}
133→	}
134→
135→	// Discover Codex sessions
136→	codexDir := codexSessionsDir()
137→	filepath.Walk(codexDir, func(path string, info os.FileInfo, err error) error {
138→		if err != nil || info.IsDir() || !strings.HasSuffix(path, ".jsonl") {
139→			return nil
140→		}
141→		candidates = append(candidates, candidate{
142→			path:    path,
143→			modTime: info.ModTime(),
144→			format:  FormatCodex,
145→		})
146→		return nil
147→	})
148→
149→	sort.Slice(candidates, func(i, j int) bool {
150→		return candidates[i].modTime.After(candidates[j].modTime)
151→	})
152→
153→	if limit > 0 && len(candidates) > limit {
154→		candidates = candidates[:limit]
155→	}
156→
157→	results := make([]*SessionInfo, len(candidates))
158→	g := new(errgroup.Group)
159→	g.SetLimit(32)
160→	for i, c := range candidates {
161→		g.Go(func() error {
162→			switch c.format {
163→			case FormatCodex:
164→				results[i] = scanCodexSessionInfo(c.path, c.modTime)
165→			default:
166→				results[i] = scanSessionInfo(c.path, c.projectDir, c.modTime)
167→			}
168→			return nil
169→		})
170→	}
171→	g.Wait()
172→
173→	var sessions []SessionInfo
174→	for _, info := range results {
175→		if info != nil {
176→			sessions = append(sessions, *info)
177→		}
178→	}
179→
180→	// Apply project filter for Codex sessions (by CWD)
181→	if projectFilter != "" {
182→		var filtered []SessionInfo
183→		for _, s := range sessions {
184→			if s.Format == FormatCodex {
185→				// Match Codex sessions by CWD-derived project dir
186→				cwdProjectDir := strings.ReplaceAll(s.CWD, "/", "-")
187→				if cwdProjectDir == projectFilter {
188→					filtered = append(filtered, s)
189→				}
190→			} else {
191→				filtered = append(filtered, s)
192→			}
193→		}
194→		sessions = filtered
195→	}
196→
197→	return sessions
198→}
199→
200→func scanSessionInfo(path, projectDir string, modTime time.Time) *SessionInfo {
201→	f, err := os.Open(path)
202→	if err != nil {
203→		return nil
204→	}
205→	defer f.Close()
206→
207→	project := extractProjectName(projectDir)
208→	scanner := bufio.NewScanner(f)
209→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
210→
211→	var preview string
212→	var cwd string
213→	found := false
214→	turns := 0
215→	lastRole := ""
216→	seenMsgID := make(map[string]bool)
217→
218→	for scanner.Scan() {
219→		var rec Record
220→		if json.Unmarshal(scanner.Bytes(), &rec) != nil {
221→			continue
222→		}
223→
224→		if rec.IsSidechain {
225→			continue
226→		}
227→
228→		switch rec.Type {
229→		case "user":
230→			if rec.Message == nil {
231→				continue
232→			}
233→			// Skip tool-result-only user messages (content is an array starting with [)
234→			if len(rec.Message.Content) > 0 && rec.Message.Content[0] == '[' {
235→				continue
236→			}
237→			text, _ := parseContent(rec.Message.Content)
238→			if text == "" {
239→				continue
240→			}
241→			found = true
242→			if lastRole != "user" {
243→				turns++
244→				lastRole = "user"
245→			}
246→			if preview == "" {
247→				if rec.CWD != "" {
248→					cwd = rec.CWD
249→				}
250→				preview = text
251→				if len(preview) > 100 {
252→					preview = preview[:100] + "..."
253→				}
254→			}
255→
256→		case "assistant":
257→			if rec.Message == nil || rec.Message.ID == "" {
258→				continue
259→			}
260→			if seenMsgID[rec.Message.ID] {
261→				continue
262→			}
263→			seenMsgID[rec.Message.ID] = true
264→			found = true
265→			if lastRole != "assistant" {
266→				turns++
267→				lastRole = "assistant"
268→			}
269→		}
270→	}
271→
272→	if !found {
273→		return nil
274→	}
275→	return &SessionInfo{
276→		Path:      path,
277→		Project:   project,
278→		CWD:       cwd,
279→		Timestamp: modTime,
280→		Preview:   preview,
281→		Turns:     turns,
282→	}
283→}
284→
285→func extractProjectName(dirName string) string {
286→	// Directory names like "-Users-ramon-src-claude-code-sandbox"
287→	// Extract just the last component
288→	parts := strings.Split(dirName, "-")
289→	// Find the last meaningful segment (after "src" or similar)
290→	for i := len(parts) - 1; i >= 0; i-- {
291→		if parts[i] == "src" && i+1 < len(parts) {
292→			return strings.Join(parts[i+1:], "-")
293→		}
294→	}
295→	// Fallback: last 2-3 components
296→	if len(parts) > 3 {
297→		return strings.Join(parts[len(parts)-3:], "-")
298→	}
299→	return dirName
300→}
