 10→
 11→func truncate(s string, n int) string {
 12→	if len(s) <= n {
 13→		return s
 14→	}
 15→	return s[:n-3] + "..."
 16→}
 17→
 18→// abbreviateLines returns first/last N lines with a "... (X lines omitted)" gap if needed.
 19→func abbreviateLines(s string, n int) string {
 20→	lines := strings.Split(s, "\n")
 21→	if len(lines) <= n*2+1 {
 22→		return s
 23→	}
 24→	var b strings.Builder
 25→	for _, l := range lines[:n] {
 26→		b.WriteString(l)
 27→		b.WriteByte('\n')
 28→	}
 29→	b.WriteString(fmt.Sprintf("... (%d lines omitted)\n", len(lines)-n*2))
 30→	for _, l := range lines[len(lines)-n:] {
 31→		b.WriteString(l)
 32→		b.WriteByte('\n')
 33→	}
 34→	return strings.TrimRight(b.String(), "\n")
 35→}
 36→
 37→func shortPath(p string) string {
 38→	home, _ := os.UserHomeDir()
 39→	if home != "" {
 40→		p = strings.TrimPrefix(p, home+"/")
 41→	}
 42→	if parts := strings.SplitN(p, "/", 4); len(parts) >= 4 && parts[0] == "src" {
 43→		return parts[1] + "/.../" + parts[len(parts)-1]
 44→	}
 45→	return p
 46→}
