 48→// countTurns returns the number of non-system entries (matching writeEntries turn numbering).
 49→func countTurns(entries []ConversationEntry) int {
 50→	n := 0
 51→	for _, e := range entries {
 52→		if e.Role != "system" {
 53→			n++
 54→		}
 55→	}
 56→	return n
 57→}
 58→
 59→func isTerminal() bool {
 60→	fi, err := os.Stdout.Stat()
 61→	if err != nil {
 62→		return false
 63→	}
 64→	return fi.Mode()&os.ModeCharDevice != 0
 65→}
 66→
 67→func renderSession(path, outputFile, imagesDir string, showThinking, summary bool, fromTurn, toTurn, lastTurns int) {
 68→	f, err := os.Open(path)
 69→	if err != nil {
 70→		fmt.Fprintf(os.Stderr, "error: %v\n", err)
 71→		os.Exit(1)
 72→	}
 73→	defer f.Close()
 74→
 75→	ps := parseSessionFile(f, path, imagesDir)
 76→
 77→	if lastTurns > 0 && fromTurn == 0 {
 78→		total := countTurns(ps.Entries)
 79→		if lastTurns < total {
 80→			fromTurn = total - lastTurns + 1
 81→		}
 82→	}
 83→
 84→	if outputFile != "" {
 85→		of, err := os.Create(outputFile)
 86→		if err != nil {
 87→			fmt.Fprintf(os.Stderr, "error: %v\n", err)
 88→			os.Exit(1)
 89→		}
 90→		defer of.Close()
 91→		writeMarkdown(of, ps, showThinking, summary, fromTurn, toTurn)
 92→		fmt.Fprintf(os.Stderr, "Wrote %s\n", outputFile)
 93→		return
 94→	}
 95→
 96→	glowPath, glowErr := exec.LookPath("glow")
 97→	if isTerminal() && glowErr == nil {
 98→		glow := exec.Command(glowPath, "-p", "-")
 99→		glow.Stdout = os.Stdout
100→		glow.Stderr = os.Stderr
101→
102→		glowIn, err := glow.StdinPipe()
103→		if err != nil {
104→			writeMarkdown(os.Stdout, ps, showThinking, summary, fromTurn, toTurn)
105→			return
106→		}
107→
108→		glow.Start()
109→		writeMarkdown(glowIn, ps, showThinking, summary, fromTurn, toTurn)
110→		glowIn.Close()
111→		glow.Wait()
112→		return
113→	}
114→
115→	writeMarkdown(os.Stdout, ps, showThinking, summary, fromTurn, toTurn)
116→}
