132→func writeMarkdown(w io.Writer, ps ParsedSession, showThinking, summary bool, fromTurn, toTurn int) {
133→	title := "Claude Code Session"
134→	versionLabel := "Claude Code"
135→	if ps.Format == FormatCodex {
136→		title = "Codex Session"
137→		versionLabel = "Codex"
138→	}
139→
140→	fmt.Fprintf(w, "# %s\n\n", title)
141→	if !ps.StartTime.IsZero() {
142→		fmt.Fprintf(w, "**Date:** %s  \n", ps.StartTime.Format("2006-01-02 15:04"))
143→	}
144→	if ps.CWD != "" {
145→		fmt.Fprintf(w, "**Project:** `%s`  \n", ps.CWD)
146→	}
147→	if ps.GitBranch != "" {
148→		fmt.Fprintf(w, "**Branch:** `%s`  \n", ps.GitBranch)
149→	}
150→	if ps.Version != "" {
151→		fmt.Fprintf(w, "**%s:** v%s  \n", versionLabel, ps.Version)
152→	}
153→	fmt.Fprintf(w, "\n---\n\n")
154→
155→	writeEntries(w, ps.Entries, showThinking, summary, fromTurn, toTurn, 0)
156→}
