158→func writeEntries(w io.Writer, entries []ConversationEntry, showThinking, summary bool, fromTurn, toTurn, depth int) {
159→	prefix := strings.Repeat("> ", depth)
160→	turnNum := 0
161→
162→	for _, entry := range entries {
163→		// System entries (compact boundary, PR links) don't count as turns
164→		if entry.Role == "system" {
165→			if summary && depth == 0 {
166→				fmt.Fprintf(w, "     %s\n", strings.Join(entry.Texts, " "))
167→			} else {
168→				fmt.Fprintf(w, "%s%s\n\n", prefix, strings.Join(entry.Texts, " "))
169→			}
170→			continue
171→		}
172→
173→		turnNum++
174→
175→		if depth == 0 && fromTurn > 0 && turnNum < fromTurn {
176→			continue
177→		}
178→		if depth == 0 && toTurn > 0 && turnNum > toTurn {
179→			break
180→		}
181→
182→		if summary && depth == 0 {
183→			switch entry.Role {
184→			case "user":
185→				preview := strings.Join(entry.Texts, " ")
186→				preview = strings.ReplaceAll(preview, "\n", " ")
187→				fmt.Fprintf(w, "%3d  **User:** %s\n", turnNum, truncate(preview, 120))
188→			case "assistant":
189→				preview := strings.Join(entry.Texts, " ")
190→				preview = strings.ReplaceAll(preview, "\n", " ")
191→				toolCount := len(entry.Tools)
192→				if preview != "" && toolCount > 0 {
193→					fmt.Fprintf(w, "%3d  **Claude:** %s (%d tools)\n", turnNum, truncate(preview, 100), toolCount)
194→				} else if preview != "" {
195→					fmt.Fprintf(w, "%3d  **Claude:** %s\n", turnNum, truncate(preview, 120))
196→				} else if toolCount > 0 {
197→					fmt.Fprintf(w, "%3d  **Claude:** (%d tools)\n", turnNum, toolCount)
198→				}
199→			}
200→			continue
201→		}
202→
203→		switch entry.Role {
204→		case "user":
205→			if depth == 0 {
206→				fmt.Fprintf(w, "## [%d] User\n\n", turnNum)
207→			} else {
208→				fmt.Fprintf(w, "%s**Prompt:**\n%s\n", prefix, prefix)
209→			}
210→			for _, text := range entry.Texts {
211→				for _, line := range strings.Split(text, "\n") {
212→					fmt.Fprintf(w, "%s%s\n", prefix, line)
213→				}
214→				fmt.Fprintf(w, "%s\n", prefix)
215→			}
216→
217→		case "assistant":
218→			if depth == 0 {
219→				fmt.Fprintf(w, "## [%d] Claude\n\n", turnNum)
220→			}
221→
222→			if showThinking && len(entry.Thinking) > 0 {
223→				for _, t := range entry.Thinking {
224→					for _, line := range strings.Split(t, "\n") {
225→						if strings.TrimSpace(line) == "" {
226→							fmt.Fprintf(w, "%s>\n", prefix)
227→						} else {
228→							fmt.Fprintf(w, "%s> *%s*\n", prefix, line)
229→						}
230→					}
231→					fmt.Fprintln(w)
232→				}
233→			}
234→
235→			for _, text := range entry.Texts {
236→				for _, line := range strings.Split(text, "\n") {
237→					fmt.Fprintf(w, "%s%s\n", prefix, line)
238→				}
239→				fmt.Fprintf(w, "%s\n", prefix)
240→			}
241→
242→			if len(entry.Tools) > 0 {
243→				for _, tc := range entry.Tools {
244→					if tc.Plan != "" {
245→						fmt.Fprintf(w, "%s### Plan\n%s\n", prefix, prefix)
246→						for _, line := range strings.Split(tc.Plan, "\n") {
247→							fmt.Fprintf(w, "%s%s\n", prefix, line)
248→						}
249→						fmt.Fprintf(w, "%s\n", prefix)
250→					} else if tc.OldStr != "" || tc.NewStr != "" {
251→						fmt.Fprintf(w, "%s> **%s** `%s`\n%s\n", prefix, tc.Name, tc.Input, prefix)
252→						if tc.OldStr != "" {
253→							var combined strings.Builder
254→							for _, line := range strings.Split(tc.OldStr, "\n") {
255→								combined.WriteString("-" + line + "\n")
256→							}
257→							for _, line := range strings.Split(tc.NewStr, "\n") {
258→								combined.WriteString("+" + line + "\n")
259→							}
260→							abbrev := abbreviateLines(strings.TrimRight(combined.String(), "\n"), 5)
261→							fmt.Fprintf(w, "%s```diff\n", prefix)
262→							for _, line := range strings.Split(abbrev, "\n") {
263→								fmt.Fprintf(w, "%s%s\n", prefix, line)
264→							}
265→							fmt.Fprintf(w, "%s```\n%s\n", prefix, prefix)
266→						} else {
267→							abbrev := abbreviateLines(tc.NewStr, 5)
268→							fmt.Fprintf(w, "%s```\n", prefix)
269→							for _, line := range strings.Split(abbrev, "\n") {
270→								fmt.Fprintf(w, "%s%s\n", prefix, line)
271→							}
272→							fmt.Fprintf(w, "%s```\n%s\n", prefix, prefix)
273→						}
274→					} else if tc.Input != "" {
275→						if tc.Meta != "" {
276→							fmt.Fprintf(w, "%s> **%s** `%s` *(%s)*\n", prefix, tc.Name, tc.Input, tc.Meta)
277→						} else {
278→							fmt.Fprintf(w, "%s> **%s** `%s`\n", prefix, tc.Name, tc.Input)
279→						}
280→					} else {
281→						fmt.Fprintf(w, "%s> **%s**\n", prefix, tc.Name)
282→					}
283→					if tc.Error != "" {
284→						fmt.Fprintf(w, "%s>\n", prefix)
285→						for _, line := range strings.Split(tc.Error, "\n") {
286→							fmt.Fprintf(w, "%s> **⚠** %s\n", prefix, line)
287→						}
288→					}
289→					if len(tc.SubConversation) > 0 {
290→						fmt.Fprintf(w, "%s\n", prefix)
291→						writeEntries(w, tc.SubConversation, showThinking, false, 0, 0, depth+1)
292→					}
293→				}
294→				fmt.Fprintln(w)
295→			}
296→		}
297→		if depth == 0 {
298→			fmt.Fprintf(w, "---\n\n")
299→		}
300→	}
301→}
