303→func listSessions(n int, projectFilter string) {
304→	sessions := findSessions(n, projectFilter)
305→	if len(sessions) == 0 {
306→		fmt.Println("No sessions found.")
307→		return
308→	}
309→
310→	fmt.Printf(" %3s  %-12s  %5s  %-30s  %s\n", "#", "Date", "Turns", "Project", "Preview")
311→	fmt.Printf(" %3s  %-12s  %5s  %-30s  %s\n", "---", "------------", "-----", "------------------------------", strings.Repeat("-", 40))
312→	for i, s := range sessions {
313→		preview := strings.ReplaceAll(s.Preview, "\n", " ")
314→		fmt.Printf(" %3d  %-12s  %5d  %-30s  %s\n",
