316→			s.Timestamp.Format("2006-01-02"),
317→			s.Turns,
318→			truncate(s.Project, 30),
319→			truncate(preview, 80),
320→		)
321→	}
322→	fmt.Printf("\nRender a session: ccmd <number>\n")
323→}
