  1→package main
  2→
  3→import (
  4→	"bufio"
  5→	"encoding/json"
  6→	"io"
  7→	"time"
  8→)
  9→
 10→// SessionFormat identifies which tool produced a session file.
 11→type SessionFormat int
 12→
 13→const (
 14→	FormatClaudeCode SessionFormat = iota
 15→	FormatCodex
 16→)
 17→
 18→// ParsedSession is the unified result of parsing any session file format.
 19→type ParsedSession struct {
 20→	Format    SessionFormat
 21→	CWD       string
 22→	GitBranch string
 23→	SessionID string
 24→	Version   string
 25→	StartTime time.Time
 26→	Entries   []ConversationEntry
 27→}
 28→
 29→// detectFormat examines the first few JSONL lines to determine the session format.
 30→func detectFormat(lines [][]byte) SessionFormat {
 31→	for _, line := range lines {
 32→		var probe struct {
 33→			Type string `json:"type"`
 34→		}
 35→		if json.Unmarshal(line, &probe) != nil {
 36→			continue
 37→		}
 38→		switch probe.Type {
 39→		case "session_meta", "event_msg", "response_item", "turn_context", "compacted":
 40→			return FormatCodex
 41→		case "message", "local_shell_call", "function_call_output":
 42→			// Old Codex format (bare items without wrapper)
 43→			return FormatCodex
 44→		case "user", "assistant", "system", "progress", "pr-link":
 45→			return FormatClaudeCode
 46→		}
 47→		// First line with no type but has "id" => old Codex header
 48→		// Continue to check next line
 49→	}
 50→	return FormatClaudeCode
 51→}
 52→
 53→// readAllLines reads all JSONL lines from a reader.
 54→func readAllLines(r io.Reader) [][]byte {
 55→	scanner := bufio.NewScanner(r)
 56→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
 57→	var lines [][]byte
 58→	for scanner.Scan() {
 59→		line := make([]byte, len(scanner.Bytes()))
 60→		copy(line, scanner.Bytes())
 61→		lines = append(lines, line)
 62→	}
 63→	return lines
 64→}
 65→
 66→// parseSessionFile detects the format and parses into a unified ParsedSession.
 67→func parseSessionFile(r io.Reader, sessionPath, imagesDir string) ParsedSession {
 68→	lines := readAllLines(r)
 69→	if len(lines) == 0 {
 70→		return ParsedSession{}
 71→	}
 72→
 73→	// Pass first few lines for format detection
 74→	probe := lines
 75→	if len(probe) > 5 {
 76→		probe = probe[:5]
 77→	}
 78→	format := detectFormat(probe)
 79→	switch format {
 80→	case FormatCodex:
 81→		return parseCodexLines(lines, sessionPath)
 82→	default:
 83→		return parseClaudeCodeLines(lines, sessionPath, imagesDir)
 84→	}
 85→}
 86→
 87→// parseClaudeCodeLines parses Claude Code JSONL lines into a ParsedSession.
 88→func parseClaudeCodeLines(lines [][]byte, sessionPath, imagesDir string) ParsedSession {
 89→	var records []Record
 90→	for _, line := range lines {
 91→		var rec Record
 92→		if json.Unmarshal(line, &rec) == nil {
 93→			records = append(records, rec)
 94→		}
 95→	}
 96→
 97→	entries := buildConversation(records, sessionPath, false, imagesDir)
 98→
 99→	ps := ParsedSession{
100→		Format:  FormatClaudeCode,
101→		Entries: entries,
102→	}
103→	for _, rec := range records {
104→		if rec.CWD != "" && ps.CWD == "" {
105→			ps.CWD = rec.CWD
106→		}
107→		if rec.GitBranch != "" && ps.GitBranch == "" {
108→			ps.GitBranch = rec.GitBranch
109→		}
110→		if rec.SessionID != "" && ps.SessionID == "" {
111→			ps.SessionID = rec.SessionID
112→		}
113→		if rec.Version != "" && ps.Version == "" {
114→			ps.Version = rec.Version
115→		}
116→		if rec.Timestamp != "" && ps.StartTime.IsZero() {
117→			ps.StartTime, _ = time.Parse(time.RFC3339Nano, rec.Timestamp)
118→		}
119→		if ps.CWD != "" && ps.GitBranch != "" && ps.SessionID != "" {
120→			break
121→		}
122→	}
123→	return ps
124→}
