 12→// parseCodexLines parses Codex rollout JSONL into a ParsedSession.
 13→// Handles both old format (bare items) and new format (wrapped in type/payload).
 14→func parseCodexLines(lines [][]byte, sessionPath string) ParsedSession {
 15→	// Detect old vs new format from first line
 16→	var probe struct {
 17→		Type string `json:"type"`
 18→	}
 19→	if len(lines) > 0 {
 20→		json.Unmarshal(lines[0], &probe)
 21→	}
 22→	isNewFormat := probe.Type == "session_meta"
 23→
 24→	if isNewFormat {
 25→		return parseCodexNew(lines, sessionPath)
 26→	}
 27→	return parseCodexOld(lines, sessionPath)
 28→}
