 30→// --- New Codex format (session_meta / event_msg / response_item / ...) ---
 31→
 32→type codexWrapper struct {
 33→	Type      string          `json:"type"`
 34→	Timestamp string          `json:"timestamp"`
 35→	Payload   json.RawMessage `json:"payload"`
 36→}
 37→
 38→type codexSessionMeta struct {
 39→	ID         string `json:"id"`
 40→	Timestamp  string `json:"timestamp"`
 41→	CWD        string `json:"cwd"`
 42→	CLIVersion string `json:"cli_version"`
 43→	Git        *struct {
 44→		Branch string `json:"branch"`
 45→	} `json:"git"`
 46→}
 47→
 48→type codexEventMsg struct {
 49→	Type    string `json:"type"`
 50→	Message string `json:"message"`
 51→}
 52→
 53→type codexResponseItem struct {
 54→	Type    string              `json:"type"` // message, reasoning, function_call, function_call_output
 55→	Role    string              `json:"role"` // user, assistant, developer
 56→	Content []codexContentBlock `json:"content"`
 57→	Phase   string              `json:"phase"` // commentary, final_answer (on assistant messages)
 58→
 59→	// function_call fields
 60→	Name      string `json:"name"`
 61→	Arguments string `json:"arguments"`
 62→	CallID    string `json:"call_id"`
 63→
 64→	// function_call_output fields
 65→	Output string `json:"output"`
 66→}
 67→
 68→type codexContentBlock struct {
 69→	Type string `json:"type"` // input_text, output_text
 70→	Text string `json:"text"`
 71→}
 72→
 73→func parseCodexNew(lines [][]byte, sessionPath string) ParsedSession {
 74→	ps := ParsedSession{Format: FormatCodex}
 75→
 76→	var raw []ConversationEntry
 77→	var currentAssistant *ConversationEntry
 78→	pendingCalls := make(map[string]*ToolCall) // call_id -> tool call
 79→
 80→	flushAssistant := func() {
 81→		if currentAssistant != nil {
 82→			// Attach pending tool call errors/results
 83→			raw = append(raw, *currentAssistant)
 84→			currentAssistant = nil
 85→		}
 86→	}
 87→
 88→	for _, line := range lines {
 89→		var w codexWrapper
 90→		if json.Unmarshal(line, &w) != nil {
 91→			continue
 92→		}
 93→
 94→		ts, _ := time.Parse(time.RFC3339Nano, w.Timestamp)
 95→
 96→		switch w.Type {
 97→		case "session_meta":
 98→			var meta codexSessionMeta
 99→			if json.Unmarshal(w.Payload, &meta) == nil {
100→				ps.CWD = meta.CWD
101→				ps.SessionID = meta.ID
102→				ps.Version = meta.CLIVersion
103→				if meta.Git != nil {
104→					ps.GitBranch = meta.Git.Branch
105→				}
106→				if t, err := time.Parse(time.RFC3339Nano, meta.Timestamp); err == nil {
107→					ps.StartTime = t
108→				}
109→			}
110→
111→		case "event_msg":
112→			var ev codexEventMsg
113→			if json.Unmarshal(w.Payload, &ev) != nil {
114→				continue
115→			}
116→			switch ev.Type {
117→			case "user_message":
118→				flushAssistant()
119→				raw = append(raw, ConversationEntry{
120→					Role:      "user",
121→					Texts:     []string{ev.Message},
122→					Timestamp: ts,
123→				})
124→			case "context_compacted":
125→				flushAssistant()
126→				raw = append(raw, ConversationEntry{
127→					Role:      "system",
128→					Texts:     []string{"*— context compacted —*"},
129→					Timestamp: ts,
130→				})
131→			}
132→
133→		case "response_item":
134→			var item codexResponseItem
135→			if json.Unmarshal(w.Payload, &item) != nil {
136→				continue
137→			}
138→
139→			switch item.Type {
140→			case "message":
141→				if item.Role == "assistant" {
142→					text := codexExtractText(item.Content)
143→					if text == "" {
144→						continue
145→					}
146→					if currentAssistant == nil {
147→						currentAssistant = &ConversationEntry{
148→							Role:      "assistant",
149→							Timestamp: ts,
150→						}
151→					}
152→					currentAssistant.Texts = append(currentAssistant.Texts, text)
153→				}
154→				// Skip developer/user response_items (system prompts)
155→
156→			case "reasoning":
157→				// Codex reasoning is encrypted; we can show the summary if available
158→				// For now, skip as we don't have access to decrypted content
159→
160→			case "function_call":
161→				if currentAssistant == nil {
162→					currentAssistant = &ConversationEntry{
163→						Role:      "assistant",
164→						Timestamp: ts,
165→					}
166→				}
167→				tc := formatCodexToolCall(item.Name, item.Arguments)
168→				currentAssistant.Tools = append(currentAssistant.Tools, tc)
169→				pendingCalls[item.CallID] = &currentAssistant.Tools[len(currentAssistant.Tools)-1]
170→
171→			case "function_call_output":
172→				if tc, ok := pendingCalls[item.CallID]; ok {
173→					// Check for errors in output
174→					if strings.Contains(item.Output, "exit_code\":1") || strings.Contains(item.Output, "\"error\"") {
175→						tc.Error = truncate(extractCommandOutput(item.Output), 500)
176→					}
177→				}
178→			}
179→		}
180→	}
181→	flushAssistant()
182→
183→	// Merge consecutive same-role entries
184→	ps.Entries = mergeEntries(raw)
185→	return ps
186→}
