188→// --- Old Codex format (bare items) ---
189→
190→type codexOldRecord struct {
191→	// Session header (first line)
192→	ID        string `json:"id"`
193→	Timestamp string `json:"timestamp"`
194→
195→	// Common
196→	Type string `json:"type"` // message, local_shell_call, function_call_output
197→
198→	// message fields
199→	Role    string              `json:"role"`
200→	Content []codexContentBlock `json:"content"`
201→
202→	// local_shell_call fields
203→	CallID string `json:"call_id"`
204→	Action *struct {
205→		Type    string   `json:"type"`
206→		Command any      `json:"command"` // string or []string
207→	} `json:"action"`
208→
209→	// function_call_output fields
210→	Output string `json:"output"`
211→}
212→
213→func parseCodexOld(lines [][]byte, sessionPath string) ParsedSession {
214→	ps := ParsedSession{Format: FormatCodex}
215→
216→	var raw []ConversationEntry
217→	var currentAssistant *ConversationEntry
218→	pendingCalls := make(map[string]*ToolCall)
219→
220→	flushAssistant := func() {
221→		if currentAssistant != nil {
222→			raw = append(raw, *currentAssistant)
223→			currentAssistant = nil
224→		}
225→	}
226→
227→	for _, line := range lines {
228→		var rec codexOldRecord
229→		if json.Unmarshal(line, &rec) != nil {
230→			continue
231→		}
232→
233→		// Session header line (has id but no type)
234→		if rec.Type == "" && rec.ID != "" {
235→			ps.SessionID = rec.ID
236→			if t, err := time.Parse(time.RFC3339Nano, rec.Timestamp); err == nil {
237→				ps.StartTime = t
238→			}
239→			continue
240→		}
241→
242→		switch rec.Type {
243→		case "message":
244→			if rec.Role == "user" {
245→				flushAssistant()
246→				text := codexExtractText(rec.Content)
247→				if text != "" {
248→					raw = append(raw, ConversationEntry{
249→						Role:  "user",
250→						Texts: []string{text},
251→					})
252→				}
253→			} else if rec.Role == "assistant" {
254→				if currentAssistant == nil {
255→					currentAssistant = &ConversationEntry{Role: "assistant"}
256→				}
257→				text := codexExtractText(rec.Content)
258→				if text != "" {
259→					currentAssistant.Texts = append(currentAssistant.Texts, text)
260→				}
261→			}
262→
263→		case "local_shell_call":
264→			if currentAssistant == nil {
265→				currentAssistant = &ConversationEntry{Role: "assistant"}
266→			}
267→			cmd := extractOldShellCommand(rec.Action)
268→			tc := ToolCall{Name: "Bash", Input: cmd}
269→			currentAssistant.Tools = append(currentAssistant.Tools, tc)
270→			pendingCalls[rec.CallID] = &currentAssistant.Tools[len(currentAssistant.Tools)-1]
271→
272→		case "function_call_output":
273→			if tc, ok := pendingCalls[rec.CallID]; ok {
274→				if strings.Contains(rec.Output, "exit_code\":1") || strings.Contains(rec.Output, "\"error\"") {
275→					tc.Error = truncate(extractCommandOutput(rec.Output), 500)
276→				}
277→			}
278→		}
279→	}
280→	flushAssistant()
281→
282→	ps.Entries = mergeEntries(raw)
283→	return ps
284→}
