286→// --- Session scanning ---
287→
288→// scanCodexSessionInfo quickly scans a Codex session file for listing metadata.
289→func scanCodexSessionInfo(path string, modTime time.Time) *SessionInfo {
290→	f, err := os.Open(path)
291→	if err != nil {
292→		return nil
293→	}
294→	defer f.Close()
295→
296→	scanner := bufio.NewScanner(f)
297→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
298→
299→	var preview string
300→	var cwd string
301→	var project string
302→	turns := 0
303→	lastRole := ""
304→	found := false
305→
306→	for scanner.Scan() {
307→		line := scanner.Bytes()
308→
309→		// Try to extract metadata from session_meta
310→		if bytes.Contains(line, []byte(`"session_meta"`)) {
311→			var w struct {
312→				Payload struct {
313→					CWD string `json:"cwd"`
314→				} `json:"payload"`
315→			}
316→			if json.Unmarshal(line, &w) == nil && w.Payload.CWD != "" {
317→				cwd = w.Payload.CWD
318→				project = extractProjectName(strings.ReplaceAll(cwd, "/", "-"))
319→			}
320→			continue
321→		}
322→
323→		// Old format: first line has id + timestamp but no type
324→		if !found && bytes.Contains(line, []byte(`"id"`)) && !bytes.Contains(line, []byte(`"type"`)) {
325→			continue
326→		}
327→
328→		// Count turns from user_message events (new format)
329→		if bytes.Contains(line, []byte(`"user_message"`)) {
330→			found = true
331→			if lastRole != "user" {
332→				turns++
333→				lastRole = "user"
334→			}
335→			if preview == "" {
336→				var w struct {
337→					Payload struct {
338→						Message string `json:"message"`
339→					} `json:"payload"`
340→				}
341→				if json.Unmarshal(line, &w) == nil && w.Payload.Message != "" {
342→					preview = w.Payload.Message
343→					if len(preview) > 100 {
344→						preview = preview[:100] + "..."
345→					}
346→				}
347→			}
348→		}
349→
350→		// Old format: bare message with role user
351→		if bytes.Contains(line, []byte(`"role":"user"`)) && bytes.Contains(line, []byte(`"input_text"`)) {
352→			found = true
353→			if lastRole != "user" {
354→				turns++
355→				lastRole = "user"
356→			}
357→			if preview == "" {
358→				var rec struct {
359→					Content []codexContentBlock `json:"content"`
360→				}
361→				if json.Unmarshal(line, &rec) == nil {
362→					text := codexExtractText(rec.Content)
363→					if text != "" {
364→						preview = text
365→						if len(preview) > 100 {
366→							preview = preview[:100] + "..."
367→						}
368→					}
369→				}
370→			}
371→		}
372→
373→		// Assistant turns
374→		isAssistant := bytes.Contains(line, []byte(`"role":"assistant"`))
375→		if isAssistant {
376→			found = true
377→			if lastRole != "assistant" {
378→				turns++
379→				lastRole = "assistant"
380→			}
381→		}
382→	}
383→
384→	if !found {
385→		return nil
386→	}
387→
388→	if project == "" {
389→		project = "codex"
390→	}
391→
392→	return &SessionInfo{
393→		Path:      path,
394→		Project:   project,
395→		CWD:       cwd,
396→		Timestamp: modTime,
397→		Preview:   preview,
398→		Turns:     turns,
399→		Format:    FormatCodex,
400→	}
401→}
