403→// scanCodexTokenUsage scans a Codex session for token usage from event_msg records.
404→func scanCodexTokenUsage(path string) (inputTokens, outputTokens int) {
405→	f, err := os.Open(path)
406→	if err != nil {
407→		return 0, 0
408→	}
409→	defer f.Close()
410→
411→	scanner := bufio.NewScanner(f)
412→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
413→
414→	for scanner.Scan() {
415→		line := scanner.Bytes()
416→		if !bytes.Contains(line, []byte(`"token_count"`)) {
417→			continue
418→		}
419→		var w struct {
420→			Payload struct {
421→				Info struct {
422→					TotalTokenUsage struct {
423→						InputTokens  int `json:"input_tokens"`
424→						OutputTokens int `json:"output_tokens"`
425→					} `json:"total_token_usage"`
426→				} `json:"info"`
427→			} `json:"payload"`
428→		}
429→		if json.Unmarshal(line, &w) == nil {
430→			u := w.Payload.Info.TotalTokenUsage
431→			if u.InputTokens > inputTokens {
432→				inputTokens = u.InputTokens
433→			}
434→			if u.OutputTokens > outputTokens {
435→				outputTokens = u.OutputTokens
436→			}
437→		}
438→	}
439→	return
440→}
