442→// --- Helpers ---
443→
444→func codexExtractText(blocks []codexContentBlock) string {
445→	var parts []string
446→	for _, b := range blocks {
447→		if b.Text != "" && (b.Type == "output_text" || b.Type == "input_text") {
448→			parts = append(parts, b.Text)
449→		}
450→	}
451→	return strings.Join(parts, "\n")
452→}
453→
454→func formatCodexToolCall(name, argsJSON string) ToolCall {
455→	switch name {
456→	case "exec_command", "shell_command":
457→		var args struct {
458→			Cmd     string `json:"cmd"`
459→			Workdir string `json:"workdir"`
460→		}
461→		if json.Unmarshal([]byte(argsJSON), &args) == nil {
462→			input := args.Cmd
463→			if args.Workdir != "" {
464→				input = args.Cmd
465→			}
466→			return ToolCall{Name: "Bash", Input: input}
467→		}
468→	case "update_plan":
469→		var args struct {
470→			Explanation string `json:"explanation"`
471→			Plan        []struct {
472→				Step   string `json:"step"`
473→				Status string `json:"status"`
474→			} `json:"plan"`
475→		}
476→		if json.Unmarshal([]byte(argsJSON), &args) == nil {
477→			var steps []string
478→			for _, p := range args.Plan {
479→				marker := "[ ]"
480→				if p.Status == "completed" {
481→					marker = "[x]"
482→				} else if p.Status == "in_progress" {
483→					marker = "[~]"
484→				}
485→				steps = append(steps, marker+" "+p.Step)
486→			}
487→			return ToolCall{Name: "Plan", Plan: strings.Join(steps, "\n")}
488→		}
489→	case "request_user_input":
490→		var args struct {
491→			Prompt string `json:"prompt"`
492→		}
493→		if json.Unmarshal([]byte(argsJSON), &args) == nil {
494→			return ToolCall{Name: "Ask", Input: args.Prompt}
495→		}
496→	}
497→	return ToolCall{Name: name, Input: truncate(argsJSON, 150)}
498→}
499→
500→func extractOldShellCommand(action *struct {
501→	Type    string `json:"type"`
502→	Command any    `json:"command"`
503→}) string {
504→	if action == nil {
505→		return ""
506→	}
507→	switch cmd := action.Command.(type) {
508→	case string:
509→		return cmd
510→	case []any:
511→		// Usually ["bash", "-lc", "actual command"]
512→		if len(cmd) >= 3 {
513→			if s, ok := cmd[2].(string); ok {
514→				return s
515→			}
516→		}
517→		var parts []string
518→		for _, c := range cmd {
519→			if s, ok := c.(string); ok {
520→				parts = append(parts, s)
521→			}
522→		}
523→		return strings.Join(parts, " ")
524→	}
525→	return ""
526→}
527→
528→// extractCommandOutput extracts the user-visible output from a Codex command result JSON.
529→func extractCommandOutput(raw string) string {
530→	var result struct {
531→		Output string `json:"output"`
532→	}
533→	if json.Unmarshal([]byte(raw), &result) == nil && result.Output != "" {
534→		return result.Output
535→	}
536→	// Sometimes the output is the raw string itself (new format)
537→	if strings.HasPrefix(raw, "Chunk ID:") || strings.HasPrefix(raw, "Wall time:") {
538→		// New format: plain text output
539→		return raw
540→	}
541→	return raw
542→}
543→
544→// mergeEntries merges consecutive same-role entries.
545→func mergeEntries(raw []ConversationEntry) []ConversationEntry {
546→	var entries []ConversationEntry
547→	for _, e := range raw {
548→		if len(entries) > 0 && entries[len(entries)-1].Role == e.Role {
549→			last := &entries[len(entries)-1]
550→			last.Texts = append(last.Texts, e.Texts...)
551→			last.Thinking = append(last.Thinking, e.Thinking...)
552→			last.Tools = append(last.Tools, e.Tools...)
553→		} else {
554→			entries = append(entries, e)
555→		}
556→	}
557→	return entries
558→}
