 11→// summaryFlag implements flag.Value for -s, acting as a bool flag that also accepts
 12→// an optional range: -s, -s=5, -s=5:10, -s=:10, -s=5:
 13→type summaryFlag struct {
 14→	enabled bool
 15→	from    int
 16→	to      int
 17→}
 18→
 19→func (f *summaryFlag) String() string { return "" }
 20→
 21→func (f *summaryFlag) Set(s string) error {
 22→	if s == "true" || s == "" {
 23→		f.enabled = true
 24→		return nil
 25→	}
 26→	if s == "false" {
 27→		f.enabled = false
 28→		return nil
 29→	}
 30→	f.enabled = true
 31→	if before, after, ok := strings.Cut(s, ":"); ok {
 32→		if before != "" {
 33→			n, err := strconv.Atoi(before)
 34→			if err != nil {
 35→				return fmt.Errorf("invalid range: %s", s)
 36→			}
 37→			f.from = n
 38→		}
 39→		if after != "" {
 40→			n, err := strconv.Atoi(after)
 41→			if err != nil {
 42→				return fmt.Errorf("invalid range: %s", s)
 43→			}
 44→			f.to = n
 45→		}
 46→	} else {
 47→		n, err := strconv.Atoi(s)
 48→		if err != nil {
 49→			return fmt.Errorf("invalid range: %s", s)
 50→		}
 51→		f.from = n
 52→	}
 53→	return nil
 54→}
