 58→// reorderArgs moves flags before positional arguments in os.Args[1:],
 59→// so Go's flag package (which stops at the first non-flag) parses them all.
 60→func reorderArgs() {
 61→	// Flags that take a following argument (not using =)
 62→	withValue := map[string]bool{
 63→		"-o": true, "-n": true, "-from": true, "-to": true, "-last": true, "-images": true,
 64→	}
 65→	var flags, positional []string
 66→	args := os.Args[1:]
 67→	for i := 0; i < len(args); i++ {
 68→		a := args[i]
 69→		if strings.HasPrefix(a, "-") {
 70→			flags = append(flags, a)
 71→			// If this flag takes a separate value and doesn't use =, consume next arg too
 72→			if withValue[a] && !strings.Contains(a, "=") && i+1 < len(args) {
 73→				i++
 74→				flags = append(flags, args[i])
 75→			}
 76→		} else {
 77→			positional = append(positional, a)
 78→		}
 79→	}
 80→	copy(os.Args[1:], append(flags, positional...))
 81→}
