 83→func main() {
 84→	if len(os.Args) >= 2 {
 85→		switch os.Args[1] {
 86→		case "claude":
 87→			runClaude(os.Args[2:])
 88→			return
 89→		case "fastcompact":
 90→			fastcompact(os.Args[2:])
 91→			return
 92→		case "precompact":
 93→			precompact()
 94→			return
 95→		}
 96→	}
 97→
 98→	// Reorder os.Args so flags come before positional args.
 99→	// Go's flag package stops parsing at the first non-flag argument,
100→	// so "ccmd 1 -s -last 20" would fail without this.
