 35→// cwdProjectDir returns the project directory name for the current working directory.
 36→// e.g., /Users/ramon/src/ccmd -> -Users-ramon-src-ccmd
 37→func cwdProjectDir() string {
 38→	cwd, err := os.Getwd()
 39→	if err != nil {
 40→		return ""
 41→	}
