 92→func findSessions(limit int, projectFilter string) []SessionInfo {
 93→	type candidate struct {
 94→		path       string
 95→		projectDir string
 96→		modTime    time.Time
 97→		format     SessionFormat
 98→	}
 99→	var candidates []candidate
100→
101→	// Discover Claude Code sessions
102→	projectsDir := claudeProjectsDir()
103→	projectDirs, err := os.ReadDir(projectsDir)
104→	if err == nil {
105→		for _, pd := range projectDirs {
106→			if !pd.IsDir() {
107→				continue
108→			}
109→			if projectFilter != "" && pd.Name() != projectFilter {
110→				continue
111→			}
112→			projPath := filepath.Join(projectsDir, pd.Name())
113→			entries, err := os.ReadDir(projPath)
114→			if err != nil {
115→				continue
116→			}
117→			for _, e := range entries {
118→				if e.IsDir() || !strings.HasSuffix(e.Name(), ".jsonl") {
119→					continue
120→				}
121→				fi, err := e.Info()
122→				if err != nil {
123→					continue
124→				}
125→				candidates = append(candidates, candidate{
126→					path:       filepath.Join(projPath, e.Name()),
127→					projectDir: pd.Name(),
128→					modTime:    fi.ModTime(),
129→					format:     FormatClaudeCode,
130→				})
131→			}
132→		}
133→	}
134→
135→	// Discover Codex sessions
136→	codexDir := codexSessionsDir()
137→	filepath.Walk(codexDir, func(path string, info os.FileInfo, err error) error {
138→		if err != nil || info.IsDir() || !strings.HasSuffix(path, ".jsonl") {
139→			return nil
140→		}
141→		candidates = append(candidates, candidate{
142→			path:    path,
143→			modTime: info.ModTime(),
144→			format:  FormatCodex,
