package main

import (
	"encoding/json"
	"flag"
	"fmt"
	"os"
	"strconv"
)

func runFiles(args []string) {
	fs := flag.NewFlagSet("files", flag.ExitOnError)
	lastN := fs.Int("last", 0, "show only the last N files")
	fs.Usage = func() {
		fmt.Fprintf(os.Stderr, "Usage: ccmd files [flags] [session-number-or-uuid-or-path]\n\n")
		fmt.Fprintf(os.Stderr, "List files read or written during a session.\n\n")
		fs.PrintDefaults()
	}
	fs.Parse(args)

	// Resolve session path
	var path string
	if fs.NArg() == 0 {
		sessions := findSessions(0, cwdProjectDir())
		if len(sessions) == 0 {
			fmt.Fprintf(os.Stderr, "error: no sessions found\n")
			os.Exit(1)
		}
		path = sessions[0].Path
	} else {
		arg := fs.Arg(0)
		if arg == "parent" {
			parentUUID := os.Getenv("CCMD_PARENT_UUID")
			if parentUUID == "" {
				fmt.Fprintf(os.Stderr, "error: CCMD_PARENT_UUID not set\n")
				os.Exit(1)
			}
			arg = parentUUID
		}
		if n, err := strconv.Atoi(arg); err == nil {
			sessions := findSessions(0, cwdProjectDir())
			if n < 1 || n > len(sessions) {
				fmt.Fprintf(os.Stderr, "error: session %d not found (have %d sessions)\n", n, len(sessions))
				os.Exit(1)
			}
			path = sessions[n-1].Path
		} else if isUUID(arg) {
			found := findSessionByUUID(arg)
			if found == "" {
				fmt.Fprintf(os.Stderr, "error: no session found for UUID %s\n", arg)
				os.Exit(1)
			}
			path = found
		} else {
			path = arg
		}
	}

	f, err := os.Open(path)
	if err != nil {
		fmt.Fprintf(os.Stderr, "error: %v\n", err)
		os.Exit(1)
	}
	defer f.Close()

	files := extractFiles(parseRecords(f))

	if *lastN > 0 && *lastN < len(files) {
		files = files[len(files)-*lastN:]
	}

	for _, fp := range files {
		fmt.Println(fp)
	}
}

// extractFiles returns unique file paths from Read/Edit/Write tool calls,
// ordered by last access.
func extractFiles(records []Record) []string {
	var all []string

	for _, rec := range records {
		if rec.Type != "assistant" || rec.Message == nil {
			continue
		}
		_, blocks := parseContent(rec.Message.Content)
		for _, b := range blocks {
			if b.Type != "tool_use" {
				continue
			}
			switch b.Name {
			case "Read", "Edit", "Write":
				var params map[string]interface{}
				if json.Unmarshal(b.Input, &params) != nil {
					continue
				}
				fp := strVal(params, "file_path")
				if fp != "" {
					all = append(all, fp)
				}
			}
		}
	}

	// Deduplicate keeping last occurrence, preserving chronological order
	seen := make(map[string]bool)
	result := make([]string, 0, len(all))
	for i := len(all) - 1; i >= 0; i-- {
		if !seen[all[i]] {
			seen[all[i]] = true
			result = append(result, all[i])
		}
	}
	for i, j := 0, len(result)-1; i < j; i, j = i+1, j-1 {
		result[i], result[j] = result[j], result[i]
	}

	return result
}

