	stats := make(map[string]*fileInfo)
	var order []string
	seen := make(map[string]bool)

	// Process in reverse to track last-access order
	for i := len(ops) - 1; i >= 0; i-- {
		op := ops[i]
		if !seen[op.path] {
			seen[op.path] = true
			order = append(order, op.path)
		}
