			}
		case "E":
			fi.edits++
			fi.added += op.added
			fi.removed += op.removed
		case "W":
			fi.writes++
			fi.written += op.written
		}
	}

	result := make([]fileInfo, 0, len(order))
	for _, path := range order {
		result = append(result, *stats[path])
	}
	return result
